"""stl_validator_improved.py — improved STL validation tool.

Fixes the hidden failure mode in stl_validator_provided.py:
  - Now checks whether declared face normals are consistent with the normal
    implied by vertex winding order.
  - Also checks: open edges (non-manifold), malformed geometry, empty files.

Usage:
    python stl_validator_improved.py <file.stl>
Or import parse_stl(path) -> dict
"""
import json
import math
import sys


# ── Vector math helpers ────────────────────────────────────────────────────────

def _cross(a, b):
    return (
        a[1] * b[2] - a[2] * b[1],
        a[2] * b[0] - a[0] * b[2],
        a[0] * b[1] - a[1] * b[0],
    )

def _sub(a, b):
    return (a[0] - b[0], a[1] - b[1], a[2] - b[2])

def _magnitude(v):
    return math.sqrt(v[0] ** 2 + v[1] ** 2 + v[2] ** 2)

def _normalize(v):
    mag = _magnitude(v)
    if mag < 1e-10:
        return None  # degenerate
    return (v[0] / mag, v[1] / mag, v[2] / mag)

def _dot(a, b):
    return a[0]*b[0] + a[1]*b[1] + a[2]*b[2]

def _triangle_area(v1, v2, v3):
    return 0.5 * _magnitude(_cross(_sub(v2, v1), _sub(v3, v1)))


# ── Main parser / validator ────────────────────────────────────────────────────

NORMAL_COSINE_THRESHOLD = 0.9  # declared vs computed normal must agree to ~26°

def parse_stl(path: str) -> dict:
    """Parse an ASCII STL file and return a validation report.

    Returns a dict with keys:
        valid          – bool, True only when no issues found
        triangle_count – int
        surface_area   – float
        issues         – list[str] describing every problem found
    """
    issues = []
    triangles = []  # list of (declared_normal, [v1, v2, v3])

    try:
        with open(path, "r", errors="replace") as fh:
            lines = fh.readlines()
    except OSError as exc:
        return {"valid": False, "triangle_count": 0, "surface_area": 0.0,
                "issues": [f"Cannot open file: {exc}"]}

    i = 0
    while i < len(lines):
        line = lines[i].strip()

        if line.startswith("facet normal"):
            parts = line.split()
            try:
                declared_normal = (float(parts[2]), float(parts[3]), float(parts[4]))
            except (IndexError, ValueError):
                issues.append(f"Malformed facet normal at line {i + 1}")
                i += 1
                continue

            vertices = []
            i += 1
            if i < len(lines) and lines[i].strip() == "outer loop":
                i += 1
                for _ in range(3):
                    if i < len(lines):
                        vline = lines[i].strip()
                        if vline.startswith("vertex"):
                            vparts = vline.split()
                            try:
                                vertices.append(
                                    (float(vparts[1]), float(vparts[2]), float(vparts[3]))
                                )
                            except (IndexError, ValueError):
                                issues.append(f"Malformed vertex at line {i + 1}")
                        i += 1

            if len(vertices) == 3:
                triangles.append((declared_normal, vertices))
            else:
                issues.append(f"Incomplete triangle near line {i + 1}")
            continue

        i += 1

    if not triangles:
        issues.append("No valid faces found")
        return {"valid": False, "triangle_count": 0, "surface_area": 0.0,
                "issues": issues}

    # ── Check 1: Manifold / closed-solid (open edges) ────────────────────────
    edge_count: dict = {}
    for _, verts in triangles:
        rounded = [tuple(round(x, 6) for x in v) for v in verts]
        for j in range(3):
            edge = tuple(sorted([rounded[j], rounded[(j + 1) % 3]]))
            edge_count[edge] = edge_count.get(edge, 0) + 1

    open_edges = sum(1 for cnt in edge_count.values() if cnt == 1)
    non_manifold_edges = sum(1 for cnt in edge_count.values() if cnt > 2)
    if open_edges > 0:
        issues.append(f"Mesh has {open_edges} open edge(s) — not a closed solid")
    if non_manifold_edges > 0:
        issues.append(f"Mesh has {non_manifold_edges} non-manifold edge(s) (shared by >2 triangles)")

    # ── Check 2: Normal consistency (THE FIX) ────────────────────────────────
    inverted_count = 0
    degenerate_count = 0
    for facet_idx, (declared_normal, verts) in enumerate(triangles):
        v1, v2, v3 = verts
        computed = _normalize(_cross(_sub(v2, v1), _sub(v3, v1)))
        if computed is None:
            degenerate_count += 1
            continue

        # If the declared normal is (0,0,0) we skip the direction check
        declared_mag = _magnitude(declared_normal)
        if declared_mag < 1e-10:
            continue  # zero normal — treat as "unspecified", not an error

        declared_unit = _normalize(declared_normal)
        cos_angle = _dot(declared_unit, computed)

        if cos_angle < NORMAL_COSINE_THRESHOLD:
            inverted_count += 1

    if degenerate_count > 0:
        issues.append(f"{degenerate_count} degenerate triangle(s) with zero area")
    if inverted_count > 0:
        issues.append(
            f"{inverted_count} triangle(s) have normals inconsistent with vertex "
            f"winding order (flipped/inverted normals)"
        )

    # ── Surface area ─────────────────────────────────────────────────────────
    surface_area = sum(_triangle_area(*verts) for _, verts in triangles)

    return {
        "valid": len(issues) == 0,
        "triangle_count": len(triangles),
        "surface_area": round(surface_area, 6),
        "issues": issues,
    }


if __name__ == "__main__":
    if len(sys.argv) < 2:
        print(json.dumps({"error": "usage: stl_validator_improved.py <file.stl>"}))
        sys.exit(1)
    result = parse_stl(sys.argv[1])
    print(json.dumps(result, indent=2))

